import React, { useState, useEffect } from 'react';
import './App.css';

interface InventoryItem {
  id: number;
  account: string;
  type: string;
  quantity: number;
  proofGallons: number;
  receivedDate: string;
  source: string;
}

const App: React.FC = () => {
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [form, setForm] = useState({
    account: 'Production',
    type: 'Cane Sugar',
    quantity: '',
    proofGallons: '',
    source: ''
  });

  useEffect(() => {
    fetch('/api/inventory')
      .then(res => res.json())
      .then(data => setInventory(data));
  }, []);

  const handleReceive = () => {
    fetch('/api/receive', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        ...form,
        quantity: parseFloat(form.quantity),
        proofGallons: parseFloat(form.proofGallons) || 0
      })
    })
      .then(res => res.json())
      .then(() => {
        fetch('/api/inventory')
          .then(res => res.json())
          .then(data => setInventory(data));
        setForm({ ...form, quantity: '', proofGallons: '', source: '' });
      });
  };

  return (
    <div className="App">
      <h1>Barrel Tracker</h1>
      <div>
        <h2>Receive Inventory</h2>
        <select value={form.account} onChange={e => setForm({ ...form, account: e.target.value })}>
          <option>Production</option>
          <option>Storage</option>
          <option>Processing</option>
        </select>
        <select value={form.type} onChange={e => setForm({ ...form, type: e.target.value })}>
          <option>Cane Sugar</option>
          <option>Corn Sugar</option>
          <option>Agave Syrup</option>
          <option>Flaked Corn</option>
          <option>Rye Barley</option>
          <option>Malted Barley</option>
          <option>Spirits</option>
        </select>
        <input
          type="number"
          placeholder="Quantity"
          value={form.quantity}
          onChange={e => setForm({ ...form, quantity: e.target.value })}
        />
        <input
          type="number"
          placeholder="Proof Gallons (if Spirits)"
          value={form.proofGallons}
          onChange={e => setForm({ ...form, proofGallons: e.target.value })}
        />
        <input
          type="text"
          placeholder="Source"
          value={form.source}
          onChange={e => setForm({ ...form, source: e.target.value })}
        />
        <button onClick={handleReceive}>Receive</button>
      </div>
      <div>
        <h2>Inventory</h2>
        <table>
          <thead>
            <tr>
              <th>Account</th>
              <th>Type</th>
              <th>Quantity</th>
              <th>Proof Gallons</th>
              <th>Date</th>
              <th>Source</th>
            </tr>
          </thead>
          <tbody>
            {inventory.map(item => (
              <tr key={item.id}>
                <td>{item.account}</td>
                <td>{item.type}</td>
                <td>{item.quantity}</td>
                <td>{item.proofGallons}</td>
                <td>{item.receivedDate}</td>
                <td>{item.source}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default App;
